                    kvp("type", "embeddedDocuments"),
                    kvp("dynamic", true|false) | make_document(kvp("typeset", "<type-set-name>")),
                    kvp("fields", make_document(
                        kvp("<field-name>", make_document(
                            // <field-mapping-definition>
